using Microsoft.AspNetCore.Mvc;
using System.Data.SqlClient;

namespace MyApi.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UsersController : ControllerBase
    {
        [HttpGet]
        public IActionResult SearchUsers(string email)
        {
            string connectionString = "Server=myserver;Database=mydatabase;User Id=myuser;Password=mypassword;";
            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                connection.Open();
                string query = "SELECT * FROM Users WHERE Email LIKE @Email";
                SqlCommand command = new SqlCommand(query, connection);
                command.Parameters.AddWithValue("@Email", "%" + email + "%");
                SqlDataReader reader = command.ExecuteReader();

                var users = new System.Collections.Generic.List<User>();
                while (reader.Read())
                {
                    User user = new User
                    {
                        Id = Convert.ToInt32(reader["Id"]),
                        Email = reader["Email"].ToString(),
                        Name = reader["Name"].ToString()
                    };
                    users.Add(user);
                }

                return Ok(users);
            }
        }
    }

    public class User
    {
        public int Id { get; set; }
        public string Email { get; set; }
        public string Name { get; set; }
    }
